use std::collections::HashMap;
use std::time::{SystemTime, UNIX_EPOCH};

struct EventLogger {
    logs: HashMap<String, Vec<String>>
}

impl EventLogger {
    fn new() -> Self {
        EventLogger { logs: HashMap::new() }
    }

    fn log_event(&mut self, event_type: &str, message: &str) {
        let entry = self.logs.entry(String::from(event_type)).or_insert_with(Vec::new);
        entry.push(format!("Time:{}, Message: {}", SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs(), message));
    }
}

macro_rules! log_error { 
    ($e:expr) => {
        let mut logger = EventLogger::new();
        logger.log_event("ERROR", &format!("{}", $e));
        println!("Successfully logged error: {}", stringify!($e));
    };
}

fn main() {
    log_error!(String::from("File access denied"));
