use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct PluginRegistry {
    plugins: Arc<Mutex<HashMap<String, Box<dyn Fn() -> String>>>>,
}

impl PluginRegistry {
    fn new() -> Self {
        PluginRegistry { plugins: Arc::new(Mutex::new(HashMap::new())) }
    }

    fn register_plugin<F>(&self, name: &str, factory: F) where F: Fn() -> String + 'static {
        let mut map = self.plugins.lock().unwrap();
        map.insert(String::from(name), Box::new(factory));
    }

    fn get_plugin(&self, name: &str) -> Option<String> {
        let map = self.plugins.lock().unwrap();
        map.get(name).map(|f| f())
    }
}

macro_rules! register_plugin_macro {
    ($registry:expr, $name:literal, $factory:block) => {
        $registry.register_plugin($name, || { 
            { 
                let result = $factory;
                println!("Running factory for {}", $name);
                result
            }
        });
    };
}

fn main() {
    let registry = PluginRegistry::new();

    register_plugin_macro!(&registry, "file_loader", {
        println!("Plugin initialized: File Loader ready.");
        String::from("FileLoaderV1")
    });

    register_plugin_macro!(&registry, "network_adapter", {
        println!("Plugin initialized: Network Adapter ready.");
        String::from("NetworkAdapterV2")
    });

    if let Some(plugin) = registry.get_plugin("file_loader") {
        println!("Successfully loaded plugin: {}", plugin);
    }

    if let Some(plugin) = registry.get_plugin("network_adapter") {
        println!("Successfully loaded plugin: {}", plugin);
    }
}
